from typing import List

class Solution:
    def maximumNumberOfStringPairs(self, words: List[str]) -> int:
        s = set(words)
        pairs = 0
        for w in words:
            # To avoid counting the same pair twice, only count when w <= reversed(w) lexicographically
            rw = w[::-1]
            if rw in s and w <= rw:
                pairs += 1
        return pairs // 2 if words else 0
```
